import{_ as e,c as s,o as i,ag as t}from"./chunks/framework.ELrfyV9R.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/reach_vb/status/2038670509768839458","created":"2026-03-31T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/隆重推出适用于 Claude Code 的 Codex 插件.md","filePath":"ai/bookmark/隆重推出适用于 Claude Code 的 Codex 插件.md","lastUpdated":1775818659000}'),p={name:"ai/bookmark/隆重推出适用于 Claude Code 的 Codex 插件.md"};function n(l,a,d,o,h,r){return i(),s("div",null,a[0]||(a[0]=[t(`<p>如果您已经在使用 Claude Code，那么这款 Codex 插件可以让您轻松地将 Codex 集成到同一工作流程中。</p><p>它有三种用途：普通的 Codex 审查、更具怀疑性的对抗性审查，以及在需要其他代理人进行第二次审查时将工作交给 Codex。</p><h2 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openai/codex-plugin-cc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex@openai-codex</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/codex:setup</span></span></code></pre></div><p>点击此处查看插件：<a href="https://github.com/openai/codex-plugin-cc" target="_blank" rel="noreferrer">https://github.com/openai/codex-plugin-cc</a> 您需要 ChatGPT 订阅（包括免费版）或 OpenAI API 密钥，以及 Node.js 18.18 或更高版本。</p><p>如果 Codex 尚未安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openai/codex</span></span></code></pre></div><p>如果 Codex 已安装但未通过身份验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><h2 id="核心命令" tabindex="-1">核心命令 <a class="header-anchor" href="#核心命令" aria-label="Permalink to &quot;核心命令&quot;">​</a></h2><p><strong>/codex:review</strong>运行标准的只读 Codex 审查。</p><p><strong>/codex:adversarial-review</strong>运行可控挑战审查。当您希望 Codex 对实现提出质疑，而不仅仅是检查实现时，请使用此选项。</p><p><strong>/codex:rescue</strong>直接将任务交给 Codex。</p><p>较长的作业可以在后台运行，可以使用**/codex:status** 、<strong>/codex:result</strong>和**/codex:cancel**来管理它们。</p><p>简单的首次运行：</p><p>何时使用</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/codex:review</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --background</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/codex:status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/codex:result</span></span></code></pre></div><p>这里的主要价值在于，无需离开 Claude Code 就能从不同的代理人那里获得真正的第二次机会。</p><p>一个好的默认模式很简单：</p><ol><li>运行 /codex:review 查看所有内容</li><li>对任何高风险内容运行 /codex:adversarial-review</li><li>当线程阻塞或您希望 Codex 接管时，请使用 /codex:rescue 命令。</li></ol><p>对抗性审查对于迁移、身份验证更改、基础架构脚本、重构以及任何存在隐藏假设而非明显语法错误的情况都特别有用。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>该插件通过本地 Codex CLI 和 Codex 应用服务器进行委托。因此，它使用与您已拥有的 Codex 相同的本地身份验证、配置、环境和 MCP 设置。</p><p>这就是它感觉轻量级的原因。它不是一个独立的运行时环境，而是 Codex，只是从 Claude Code 内部调用而已。</p><h2 id="可选审查门" tabindex="-1">可选审查门 <a class="header-anchor" href="#可选审查门" aria-label="Permalink to &quot;可选审查门&quot;">​</a></h2><p>您还可以启用审核门：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/codex:setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --enable-review-gate</span></span></code></pre></div><p>这样可以阻止 Claude Code 在 Codex 审查完成之前退出。</p><p>虽然有用，但需谨慎使用。它可能会导致 Claude/Codex 循环过长，并迅速耗尽使用次数限制。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>这个插件提供了一种简单的方法，让您在保持 Claude Code 工作流程的同时，还能利用 Codex 的优势。</p><p>安装它，运行 /codex:setup，使用 /codex:review 作为你的默认第二遍审查，当你需要比常规审查更深入的审查时，可以使用 /codex:adversarial-review 或 /codex:rescue。</p><p>点击此处查看插件：<a href="https://github.com/openai/codex-plugin-cc" target="_blank" rel="noreferrer">https://github.com/openai/codex-plugin-cc</a></p>`,33)]))}const g=e(p,[["render",n]]);export{k as __pageData,g as default};
